mapper.select:
SELECT j.WORK_INDCT_NUM, j.CUST_NUM, j.EQUT_CD, j.PROD_CD, p.PROD_MM AS PROD_NM, p.CUST_PROD_NUM AS PROD_NUM, COALESCE(c.CUST_COMP_NM, j.CUST_NUM) AS CUST_NM, DATE_FORMAT(j.START_DTTM, '%Y-%m-%d %H:%i:%s') AS START_DTTM, DATE_FORMAT(j.END_DTTM, '%Y-%m-%d %H:%i:%s') AS END_DTTM FROM tb_jacup j LEFT JOIN sat_prod p ON p.PROD_CD = j.PROD_CD LEFT JOIN sat_cust c ON c.CUST_NUM = j.CUST_NUM WHERE j.START_DTTM IS NOT NULL AND j.START_DTTM BETWEEN #{from} AND #{to}
AND j.EQUT_CD = #{equtCd}
ORDER BY j.START_DTTM ASC
